namespace App\Services;

use Twilio\Rest\Client;
use Exception;

class TwilioSmsService
{
    protected Client $twilioClient;
    protected string $fromNumber;

    /**
     * TwilioSmsService constructor.
     *
     * @param Client $twilioClient The Twilio REST client instance.
     */
    public function __construct(Client $twilioClient)
    {
        $this->twilioClient = $twilioClient;
        $this->fromNumber = config('services.twilio.from');

        if (empty($this->fromNumber)) {
            throw new Exception('Twilio "from" phone number is not configured.');
        }
    }

    /**
     * Send an SMS message via Twilio.
     *
     * @param string $to The recipient's phone number (e.g., "+1234567890").
     * @param string $message The body of the SMS message.
     * @return \Twilio\Rest\Api\V2010\Account\MessageInstance
     * @throws Exception If the message sending fails.
     */
    public function sendSms(string $to, string $message): \Twilio\Rest\Api\V2010\Account\MessageInstance
    {
        try {
            $messageInstance = $this->twilioClient->messages->create(
                $to,
                [
                    'from' => $this->fromNumber,
                    'body' => $message,
                ]
            );

            return $messageInstance;
        } catch (\Twilio\Exceptions\TwilioException $e) {
            // Log the error or handle it as needed
            throw new Exception("Failed to send SMS via Twilio: " . $e->getMessage(), $e->getCode(), $e);
        } catch (Exception $e) {
            throw new Exception("An unexpected error occurred while sending SMS: " . $e->getMessage(), $e->getCode(), $e);
        }
    }
}

